/**
 * Materialization-axis harness for a wide 100k-row SELECT page and RDF 1.2 triple-term resolution. Result values are
 * fully inspected while streaming so a future batched dictionary path cannot be optimized away by the benchmark.
 */
@Warmup(iterations = 3, time = 1, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode(Mode.AverageTime)
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx4G" })
@Measurement(iterations = 5, time = 1, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
@Threads(1)
public class MaterializationBenchmark {

	private static final String EX = "http://example.com/materialization/";
	private static final String LABEL_SUFFIX = "-0123456789abcdef0123456789abcdef";
	private static final String NATIVE_ENABLED = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String PARALLEL_ENABLED = "rdf4j.lmdb.parallel.enabled";
	private static final long DIGEST_OFFSET = 0xcbf29ce484222325L;
	private static final long DIGEST_PRIME = 0x100000001b3L;

	@Benchmark
	public long materializeSelectPage(MaterializationState state) {
		return state.runAndVerify(Workload.SELECT_PAGE);
	}

	@Benchmark
	public long materializeTripleTerms(MaterializationState state) {
		return state.runAndVerify(Workload.TRIPLE_TERMS);
	}

	@State(Scope.Benchmark)
	public static class MaterializationState {

		@Param({ "100000" })
		public int inputRows;

		private File dataDir;
		private SailRepository repository;
		private EnumMap<Workload, QueryDigest> expectedDigests;
		private EnumMap<Workload, String> executionPaths;
		private Map<String, String> previousProperties;

		@Setup(Level.Trial)
		public void setUp() {
			if (inputRows <= 0) {
				throw new IllegalArgumentException("inputRows must be positive");
			}
			captureProperties();
			System.setProperty(NATIVE_ENABLED, "true");
			System.setProperty(PARALLEL_ENABLED, "false");
			dataDir = Files.newTemporaryFolder();
			repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
			loadData();
			expectedDigests = expectedDigests(inputRows);
			executionPaths = new EnumMap<>(Workload.class);
			for (Workload workload : Workload.values()) {
				verifyDigest(workload, runWorkload(workload));
				executionPaths.put(workload, executionPath(workload));
			}
		}

		private void captureProperties() {
			previousProperties = new LinkedHashMap<>();
			for (String property : List.of(NATIVE_ENABLED, PARALLEL_ENABLED)) {
				previousProperties.put(property, System.getProperty(property));
			}
		}

		private void loadData() {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				ValueFactory vf = connection.getValueFactory();
				IRI labelPredicate = vf.createIRI(EX, "label");
				IRI valuePredicate = vf.createIRI(EX, "value");
				IRI termPredicate = vf.createIRI(EX, "term");
				IRI embeddedPredicate = vf.createIRI(EX, "embeddedPredicate");
				connection.begin();
				for (int row = 0; row < inputRows; row++) {
					IRI subject = vf.createIRI(EX, "row/" + row);
					Literal value = vf.createLiteral(row);
					connection.add(subject, labelPredicate, vf.createLiteral(label(row)));
					connection.add(subject, valuePredicate, value);
					connection.add(subject, termPredicate, vf.createTripleTerm(subject, embeddedPredicate, value));
				}
				connection.commit();
			}
		}

		@TearDown(Level.Trial)
		public void tearDown() throws IOException {
			try {
				if (repository != null) {
					repository.shutDown();
				}
			} finally {
				try {
					if (dataDir != null) {
						FileUtil.deleteDir(dataDir);
					}
				} finally {
					restoreProperties();
				}
			}
		}

		long runAndVerify(Workload workload) {
			QueryDigest actual = runWorkload(workload);
			verifyDigest(workload, actual);
			return actual.folded();
		}

		QueryDigest runWorkload(Workload workload) {
			long rows = 0L;
			long digest = 0L;
			try (SailRepositoryConnection connection = repository.getConnection();
					TupleQueryResult result = connection.prepareTupleQuery(workload.query).evaluate()) {
				while (result.hasNext()) {
					digest += workload == Workload.SELECT_PAGE
							? selectDigest(result.next())
							: tripleTermDigest(result.next());
					rows++;
				}
			}
			return new QueryDigest(rows, digest);
		}

		EnumMap<Workload, String> executionPaths() {
			return new EnumMap<>(executionPaths);
		}

		private String executionPath(Workload workload) {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				GenericPlanNode plan = connection.prepareTupleQuery(workload.query)
						.explain(Explanation.Level.Telemetry)
						.toGenericPlanNode();
				String path = findExecutionPath(plan);
				if (path == null) {
					throw new IllegalStateException(workload + ": telemetry did not report nativeExecutionPath");
				}
				return path;
			}
		}

		private void verifyDigest(Workload workload, QueryDigest actual) {
			QueryDigest expected = expectedDigests.get(workload);
			if (!expected.equals(actual)) {
				throw new IllegalStateException(workload + ": expected " + expected + " but got " + actual);
			}
		}

		private void restoreProperties() {
			if (previousProperties == null) {
				return;
			}
			for (Map.Entry<String, String> property : previousProperties.entrySet()) {
				if (property.getValue() == null) {
					System.clearProperty(property.getKey());
				} else {
					System.setProperty(property.getKey(), property.getValue());
				}
			}
		}
	}

	private static long selectDigest(BindingSet bindings) {
		Value subject = bindings.getValue("row");
		Value label = bindings.getValue("label");
		Value value = bindings.getValue("value");
		if (!(subject instanceof IRI) || !(label instanceof Literal) || !(value instanceof Literal literal)) {
			throw new IllegalStateException("SELECT_PAGE returned an unexpected row: " + bindings);
		}
		return rowDigest(subject.stringValue().hashCode(), label.stringValue().hashCode(), literal.longValue());
	}

	private static long tripleTermDigest(BindingSet bindings) {
		Value value = bindings.getValue("term");
		if (!(value instanceof TripleTerm term) || !(term.getObject()instanceof Literal literal)) {
			throw new IllegalStateException("TRIPLE_TERMS returned an unexpected row: " + bindings);
		}
		return rowDigest(term.getSubject().stringValue().hashCode(), term.getPredicate().stringValue().hashCode(),
				literal.longValue());
	}

	private static EnumMap<Workload, QueryDigest> expectedDigests(int inputRows) {
		EnumMap<Workload, QueryDigest> expected = new EnumMap<>(Workload.class);
		long selectDigest = 0L;
		long tripleDigest = 0L;
		int predicateHash = (EX + "embeddedPredicate").hashCode();
		for (int row = 0; row < inputRows; row++) {
			int subjectHash = (EX + "row/" + row).hashCode();
			selectDigest += rowDigest(subjectHash, label(row).hashCode(), row);
			tripleDigest += rowDigest(subjectHash, predicateHash, row);
		}
		expected.put(Workload.SELECT_PAGE, new QueryDigest(inputRows, selectDigest));
		expected.put(Workload.TRIPLE_TERMS, new QueryDigest(inputRows, tripleDigest));
		return expected;
	}

	private static String label(int row) {
		return "materialized-label-" + row + LABEL_SUFFIX;
	}

	private static long rowDigest(long first, long second, long third) {
		long digest = (DIGEST_OFFSET ^ first) * DIGEST_PRIME;
		digest = (digest ^ second) * DIGEST_PRIME;
		return (digest ^ third) * DIGEST_PRIME;
	}

	private static String findExecutionPath(GenericPlanNode node) {
		if (node == null) {
			return null;
		}
		String path = node.getStringMetricActual("nativeExecutionPath");
		if (path != null) {
			return path;
		}
		if (node.getPlans() != null) {
			for (GenericPlanNode child : node.getPlans()) {
				String found = findExecutionPath(child);
				if (found != null) {
					return found;
				}
			}
		}
		return null;
	}

	record QueryDigest(long rowCount, long digest) {
		long folded() {
			return digest ^ Long.rotateLeft(rowCount, 17);
		}
	}

	enum Workload {
		SELECT_PAGE(
				"SELECT ?row ?label ?value WHERE { ?row <" + EX + "label> ?label ; <" + EX
						+ "value> ?value }"),
		TRIPLE_TERMS("SELECT ?term WHERE { ?row <" + EX + "term> ?term }");

		private final String query;

		Workload(String query) {
			this.query = query;
		}
	}
}
